import{_ as n,C as e,o as l,c as p,ag as t,E as i}from"./chunks/framework.CAXxHpAX.js";const g=JSON.parse('{"title":"16. 能力地图","description":"把全书能力沉淀为 SQL、建模、链路、选型和治理五类能力。","frontmatter":{"title":"16. 能力地图","description":"把全书能力沉淀为 SQL、建模、链路、选型和治理五类能力。","prev":{"text":"15. 推荐学习顺序","link":"/chapters/15-learning-order"},"next":{"text":"17. 最终学习目标","link":"/chapters/17-final-goals"}},"headers":[],"relativePath":"chapters/16-capability-map.md","filePath":"chapters/16-capability-map.md"}'),r={name:"chapters/16-capability-map.md"};function d(o,a,c,h,b,u){const s=e("Mermaid");return l(),p("div",null,[a[0]||(a[0]=t('<h1 id="_16-能力地图" tabindex="-1">16. 能力地图 <a class="header-anchor" href="#_16-能力地图" aria-label="Permalink to &quot;16. 能力地图&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>把全书能力沉淀为 SQL、建模、链路、选型和治理五类能力。</p></div><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',4)),i(s,{code:"mindmap%0A%20%20root((%E8%83%BD%E5%8A%9B%E5%9C%B0%E5%9B%BE))%0A%20%20%20%20SQL%20%E8%83%BD%E5%8A%9B%0A%20%20%20%20%E5%BB%BA%E6%A8%A1%E8%83%BD%E5%8A%9B%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E9%93%BE%E8%B7%AF%E8%83%BD%E5%8A%9B%0A%20%20%20%20%E7%B3%BB%E7%BB%9F%E9%80%89%E5%9E%8B%E8%83%BD%E5%8A%9B%0A%20%20%20%20%E6%B2%BB%E7%90%86%E8%83%BD%E5%8A%9B%0A"}),a[1]||(a[1]=t(`<p>完成本书后，能力不应该表现为“知道很多工具名”，而应该表现为能在具体系统问题中做判断。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>能力地图分为五类：SQL 能力、建模能力、数据链路能力、系统选型能力、治理能力。</p><p>很多学习者的问题不是没学过工具，而是无法把工具放到系统问题中判断：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这个查询应该留在 PostgreSQL，还是进 ClickHouse？</span></span>
<span class="line"><span>这个指标冲突是 SQL 问题、建模问题，还是治理问题？</span></span>
<span class="line"><span>这个 RAG 效果差，是向量库问题，还是文档解析和评测问题？</span></span>
<span class="line"><span>这个实时链路延迟高，是 Kafka、Flink、Sink，还是业务期望不合理？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>本章把全书能力收束成一张检查表。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>真正的数据库和数据平台能力，不是知道每个系统的定义，而是能判断问题属于哪一层、该用什么机制解决、会引入什么代价、哪些边界不能越过。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="一、sql-能力" tabindex="-1">一、SQL 能力 <a class="header-anchor" href="#一、sql-能力" aria-label="Permalink to &quot;一、SQL 能力&quot;">​</a></h3><p>SQL 能力是大数据方向的基础硬技能。</p><p>包括：</p><ul><li>查询。</li><li>聚合。</li><li>JOIN。</li><li>CTE。</li><li>窗口函数。</li><li>指标计算。</li></ul><p>合格标准不是会写语法，而是能把业务问题变成可解释 SQL。</p><p>例如：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务问题：新用户 7 日留存是多少？</span></span>
<span class="line"><span>  -&gt; 定义新用户</span></span>
<span class="line"><span>  -&gt; 定义回访</span></span>
<span class="line"><span>  -&gt; 明确时间字段</span></span>
<span class="line"><span>  -&gt; 去重 user_id</span></span>
<span class="line"><span>  -&gt; 按注册日期分组</span></span>
<span class="line"><span>  -&gt; 输出留存率</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="二、建模能力" tabindex="-1">二、建模能力 <a class="header-anchor" href="#二、建模能力" aria-label="Permalink to &quot;二、建模能力&quot;">​</a></h3><p>建模能力决定数据是否可分析、可复用、可治理。</p><p>包括：</p><ul><li>业务建模。</li><li>事实表。</li><li>维度表。</li><li>宽表。</li><li>分层模型。</li><li>向量数据模型。</li><li>图数据模型。</li></ul><p>核心问题始终是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一行代表什么？</span></span>
<span class="line"><span>字段描述什么？</span></span>
<span class="line"><span>关系如何表达？</span></span>
<span class="line"><span>指标如何计算？</span></span>
<span class="line"><span>权限如何继承？</span></span>
<span class="line"><span>版本如何追踪？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="三、数据链路能力" tabindex="-1">三、数据链路能力 <a class="header-anchor" href="#三、数据链路能力" aria-label="Permalink to &quot;三、数据链路能力&quot;">​</a></h3><p>数据链路能力决定数据能否持续进入平台。</p><p>包括：</p><ul><li>批处理。</li><li>流处理。</li><li>CDC。</li><li>ETL。</li><li>ELT。</li><li>Embedding Pipeline。</li><li>Graph Construction Pipeline。</li><li>调度。</li><li>质量校验。</li></ul><p>核心判断是：</p><blockquote><p>数据链路不是一次性脚本，而是可重跑、可观察、可恢复、可追踪的工程系统。</p></blockquote><h3 id="四、系统选型能力" tabindex="-1">四、系统选型能力 <a class="header-anchor" href="#四、系统选型能力" aria-label="Permalink to &quot;四、系统选型能力&quot;">​</a></h3><p>系统选型不是背优缺点，而是在需求和边界之间做匹配。</p><table tabindex="0"><thead><tr><th>系统</th><th>主要定位</th></tr></thead><tbody><tr><td>PostgreSQL</td><td>业务库 / 中小分析 / pgvector / 元数据</td></tr><tr><td>ClickHouse</td><td>高性能 OLAP</td></tr><tr><td>Doris</td><td>实时数仓 / BI</td></tr><tr><td>Spark</td><td>离线大规模计算</td></tr><tr><td>Flink</td><td>实时流计算</td></tr><tr><td>Kafka</td><td>事件流 / 数据总线</td></tr><tr><td>Iceberg</td><td>湖仓表格式</td></tr><tr><td>Trino</td><td>联邦查询</td></tr><tr><td>DuckDB</td><td>本地分析</td></tr><tr><td>Milvus / Qdrant</td><td>向量检索</td></tr><tr><td>Neo4j / NebulaGraph</td><td>图关系分析</td></tr></tbody></table><p>选型时至少问：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>数据规模多大？</span></span>
<span class="line"><span>延迟要求多高？</span></span>
<span class="line"><span>写入模式是什么？</span></span>
<span class="line"><span>查询模式是什么？</span></span>
<span class="line"><span>一致性要求是什么？</span></span>
<span class="line"><span>团队是否能运维？</span></span>
<span class="line"><span>是否需要治理和权限？</span></span>
<span class="line"><span>是否已有系统可以满足？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="五、治理能力" tabindex="-1">五、治理能力 <a class="header-anchor" href="#五、治理能力" aria-label="Permalink to &quot;五、治理能力&quot;">​</a></h3><p>治理能力让数据系统长期可信。</p><p>包括：</p><ul><li>元数据管理。</li><li>数据质量。</li><li>数据血缘。</li><li>指标治理。</li><li>向量数据治理。</li><li>图谱治理。</li><li>权限安全。</li><li>调度运维。</li><li>成本优化。</li></ul><p>治理不是“平台成熟以后再做”，而是从第一条数据链路、第一张指标表、第一批文档向量开始就应该建立基本规则。</p><h3 id="六、能力分级" tabindex="-1">六、能力分级 <a class="header-anchor" href="#六、能力分级" aria-label="Permalink to &quot;六、能力分级&quot;">​</a></h3><p>能力地图还需要分级，否则容易把“听过”“会跑 Demo”和“能做系统判断”混在一起。</p><table tabindex="0"><thead><tr><th>能力层级</th><th>表现</th><th>不合格信号</th></tr></thead><tbody><tr><td>入门</td><td>能解释概念，能完成单点练习</td><td>只能复述定义，不能说明它解决什么问题</td></tr><tr><td>可用</td><td>能在一个项目中交付 SQL、模型、链路或治理清单</td><td>产物能跑，但没有口径、血缘、质量或边界说明</td></tr><tr><td>熟练</td><td>能定位问题属于 SQL、建模、链路、选型还是治理</td><td>遇到问题只会更换工具，不会拆解原因</td></tr><tr><td>系统化</td><td>能设计端到端链路，并说明每层取舍和失败模式</td><td>架构图堆组件，但没有数据粒度、延迟、一致性和权限边界</td></tr><tr><td>可带人</td><td>能把能力拆成任务、验收标准和复盘机制</td><td>团队依赖个人经验，不能沉淀为稳定流程</td></tr></tbody></table><p>对本书来说，最低目标不是“入门”，而是达到“可用”：能用可检查产物证明自己理解了系统机制。最终目标是靠第 14 章项目和第 17 章毕业设计逼近“熟练”和“系统化”。</p><h3 id="七、能力之间的依赖关系" tabindex="-1">七、能力之间的依赖关系 <a class="header-anchor" href="#七、能力之间的依赖关系" aria-label="Permalink to &quot;七、能力之间的依赖关系&quot;">​</a></h3><p>这些能力不是并列清单。它们有依赖顺序：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SQL 表达能力</span></span>
<span class="line"><span>  -&gt; 建模能力</span></span>
<span class="line"><span>  -&gt; 数据链路能力</span></span>
<span class="line"><span>  -&gt; 系统选型能力</span></span>
<span class="line"><span>  -&gt; 治理能力</span></span>
<span class="line"><span>  -&gt; AI 数据应用能力</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>SQL 能力不足时，指标会错。建模能力不足时，表会不可复用。链路能力不足时，数据会不稳定。选型能力不足时，系统会过度复杂或性能不足。治理能力不足时，数据会失去信任。AI 数据应用能力不足时，向量、图和模型会变成不可追溯的黑盒。</p><h3 id="深度展开-能力地图如何落到真实系统" tabindex="-1">深度展开：能力地图如何落到真实系统 <a class="header-anchor" href="#深度展开-能力地图如何落到真实系统" aria-label="Permalink to &quot;深度展开：能力地图如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>读完整本书后，需要把知识点转成能力结构，否则很容易仍然停留在工具记忆。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是已完成的 SQL、建模、链路、OLAP、湖仓、AI 检索、图分析和治理练习。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是把能力拆成查询表达、数据建模、链路工程、系统选型、治理可信和 AI 数据应用六类，再为每类定义可验证表现。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>真实团队会用能力地图做培养、面试、项目分工和技术评审。它把“会不会某个工具”改成“能否解释问题、设计边界、验证结果”。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>能力地图不是证书目录。一个人可以不会所有工具，但必须能判断工具为什么出现、什么时候不该用、如何验证效果。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>简历堆满工具但项目说不清边界</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>只会写任务不会做质量检查</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>只会搭 RAG 不会治理数据来源</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>系统选型只看流行度</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>用能力地图给自己的项目打分：每类能力列出证据、缺口、下一步补强任务和验收方式。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>能力地图是第 15 章学习顺序的验收层，也是第 17 章最终学习目标的前置检查。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>学习顺序</span></span>
<span class="line"><span>  -&gt; 形成能力</span></span>
<span class="line"><span>  -&gt; 通过项目验证</span></span>
<span class="line"><span>  -&gt; 达到最终目标</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>每一项能力都应该能在项目中找到证据：SQL 文件、数据模型、DAG、架构图、选型说明、治理规则、评测记录或复盘文档。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>面对“实时 GMV 看板和最终财务 GMV 不一致”这个问题，能力地图可以帮助定位：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SQL 能力：两个 GMV 是否过滤条件一致？</span></span>
<span class="line"><span>建模能力：实时明细和离线明细的一行粒度是否一致？</span></span>
<span class="line"><span>数据链路能力：CDC 是否丢失、重复或延迟？</span></span>
<span class="line"><span>系统选型能力：实时看板是否被误当财务结算系统？</span></span>
<span class="line"><span>治理能力：指标是否有统一定义、血缘和负责人？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这个案例说明，真实问题通常不是单点工具问题，而是多类能力的组合判断。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：能力等于工具清单。</strong></p><p>工具只是载体。能力是能把问题、机制、边界和代价讲清楚，并能用产物验证。</p><p><strong>误区二：SQL 能力和工程能力可以分开。</strong></p><p>SQL 是表达计算的基础，但真实平台还要考虑链路、调度、质量、权限和可恢复性。</p><p><strong>误区三：治理能力是管理岗才需要。</strong></p><p>任何写表、写指标、写检索链路、写图谱关系的人，都在生产可被复用或误用的数据资产，因此都需要治理意识。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>用本章五类能力审查第 14 章中的任意一个项目。</p><p>输出一张表：</p><table tabindex="0"><thead><tr><th>能力</th><th>当前证据</th><th>缺口</th><th>下一步</th></tr></thead><tbody><tr><td>SQL 能力</td><td>SQL 文件、指标口径</td><td>例如缺少留存 SQL</td><td>补查询和口径说明</td></tr><tr><td>建模能力</td><td>表结构、ER 图</td><td>例如粒度不清</td><td>补事实表定义</td></tr><tr><td>数据链路能力</td><td>DAG、同步脚本</td><td>例如不能重跑</td><td>补幂等和补数</td></tr><tr><td>系统选型能力</td><td>架构说明</td><td>例如选型无边界</td><td>补取舍说明</td></tr><tr><td>治理能力</td><td>质量规则、权限</td><td>例如无血缘</td><td>补元数据记录</td></tr></tbody></table><p>再补一列“验收证据”，不要只写“已完成”。例如：</p><ul><li>SQL 能力的证据是 <code>.sql</code> 文件、执行记录、结果样例和口径说明。</li><li>建模能力的证据是表结构、粒度说明、主键、分区、维度和指标定义。</li><li>链路能力的证据是 DAG、重跑策略、失败恢复、对账记录和延迟记录。</li><li>选型能力的证据是需求边界、备选方案、取舍理由和成本估算。</li><li>治理能力的证据是元数据、血缘、质量规则、权限策略和审计记录。</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>能力地图的核心是迁移。</p><p>你在 PostgreSQL 中理解的表、行、列、主键、索引、事务、查询路径，会迁移到数仓事实表、湖仓表格式、向量元数据、图实体关系和数据治理。</p><p>真正的能力不是知道所有系统，而是知道每个系统在什么问题上出现，解决什么，不解决什么，如何与前后系统协作。</p><p>下一章用最终目标把这些能力收束为读者完成本书后应达到的状态。</p>`,96))])}const k=n(r,[["render",d]]);export{g as __pageData,k as default};
